from fractions import Fraction
from math import ceil, floor, log
def cantor_stage(k):
    intervals = [(Fraction(0), Fraction(1))]
    for _ in range(k):
        new_intervals = []
        for a, b in intervals:
            new_intervals.append((a, (2*a + b)/3))
            new_intervals.append((((a + 2*b)/3), b))
        intervals = new_intervals
    return intervals
def cells_hit(n, interval):
    u, v = interval
    t = 2**n
    L = max(0, ceil(t*u - 1))
    R = min(t - 1, floor(t*v))
    if L <= R:
        return (L, R)
    return None
def a(n):
    k = ceil(n*log(2, 3)) + 2
    stage = cantor_stage(k)
    ranges = [r for r in (cells_hit(n, I) for I in stage) if r is not None]
    ranges.sort()
    merged = []
    curL, curR = ranges[0]
    for L, R in ranges[1:]:
        if L <= curR + 1:
            curR = max(curR, R)
        else:
            merged.append((curL, curR))
            curL, curR = L, R
    merged.append((curL, curR))
    return sum(R - L + 1 for L, R in merged)
print([a(n) for n in range(36)])

